const Q_ECONOMICS_2022_MODEL_I=[{"id": "objective>Economics>2022 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Scale of preference shows</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">incomes of consumers in order of size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utilities enjoyed by consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost of goods consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer's wants in order of priority</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scale of preference is a table showing an individual wants arranged in a chronological order or it shows an individual wants in order of priority.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2022 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">There is unemployment of resources when production is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">within the production possibility curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">outside the production possibility curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">along the production possibility curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequate to meet market demand</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Point inside the production possibility curve indicate that resources are not fully employed or inefficient use of resources or there is widespread unemployment.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2022 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristic of natural resources is that they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are unlimited in supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have high cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are free gifts of nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">do not command any price</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural resources exist naturally unlike man made resources that are created by human beings. The existence of natural resources is not attributed to any human activities, they are acts of nature.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>2022 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major disadvantage of a capitalist economy is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leads to low production of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">requires large number of officials to operate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">considers individual consumers' satisfaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">worsens income inequality among the citizens</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the disadvantage of capitalism is that wealth and control of means of production is concentrated in the hands of every few individuals. The rich families alwalys control the wealth of the society.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2022 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mining sector of an economy contributes 60% to the Gross Domestic Product(GDP). If the GDP is $540, what is the contribution of the mining sector?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">$ 90.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">$ 180.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">$ 324.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">$ 350.00</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The contribution of a sector to the Gross Domestic Product (GDP) is calculated as a percentage of the total GDP. In this case, the mining sector contributes 60% to the GDP. Therefore, to find the contribution of the mining sector, we multiply the total GDP by the percentage contribution of the mining sector. That is, $540 * 60/100 = $324. Therefore, the mining sector contributes $324 to the GDP.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2022 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The increase in the demand for a commodity may lead to a decrease in the demand for another if both are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in complementary demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the same quality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in composite demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in competitive demand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Competitive demand is also known as subtituted demand. These are alternative commodities which can satisfy similar wants wants i.e they posses identical utilities. An increased in demand for one will lead to a decreased demand for the other.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2022 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve for goods of ostentation is usually</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negatively sloped</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positively sloped</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ostentation goods are goods that are expensive such as jewelries, gold wrist watch etc. The higher the price,  the higher the quantity demanded. Therefore, the relationship between price and quantity demanded is positive.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2022 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> PN equals average revenue or marginal revenue cure of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An imperfect competitive firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monopoly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a perfectly competitive firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monopolistic competitive firm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The figure PN in the diagram is Average revenue or marginal revenue of a perfect market or perfectly competitive firm.</div>", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE"}, {"id": "objective>Economics>2022 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the quantity demanded of a commodity increases from 20 units to 30 units when there is an increase in price from $4.00 to $5.00, the elasticity of demand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.65</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">e = ∆Qd/∆P   x P/Qd <br/>  <br/> =  <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">30 - 20</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 5 - 4</span>   x   <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 20</span> <br/>  <br/>  = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">10</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1</span>   x  <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">20</span> <br/>  <br/> =  2</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2022 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supply curve of a locally-produced good may shift to the right if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is an increase in taxes on inputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government increases subsidies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban migration is encouraged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the price of the commodity increases</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supply curve can shift to the right (increase in supply) if the government increases subsidies. This is because subsidies reduce the cost of production, encouraging producers to produce more.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2022 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In perfectly elastic supply, the supply curve</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is vertical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is horizontal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slopes upward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slopes downward</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect elastic supply curve is the one in which the supply curve is perfectly horizontal. It is a theoretical curve and such a curve does not actually exist in practice.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2022 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country's budget allocation to various sectors of the economy is shown in the pie chart below. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use it to answer this question <br/>  <br/> If the budget of the country was $7,200, how much is allocated to Education? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">$2,400.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">$2,000.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">$1,200.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">$1,000.00</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the budget of the country was $7,200, how much is allocated to Education?  <br/>  <br/> = 120 /360  x 7200 <br/>  <br/> = 2400</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2022 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> A country's budget allocation to various sectors of the economy is shown in the pie chart below. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use it to answer this question <br/> What is the ratio of expenditure on health to Agriculture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2: 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5:4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Health = 60/360  x 7200 <br/> = 1200 <br/>  <br/> Agriculture = 80/360  x 7200 <br/> = 1600 <br/>  <br/> The ratio of expenditure on health to agriculture = 1200/1600 <br/> = 3:4</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2022 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer of a single commodity is in equilibrium when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">he can equate his demand with price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">he equates marginal utility and price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">he can equate his marginal and total utilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">his marginal utility is equal to zero</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer is in equilibrium when the marginal utility equal to the price of the commodity i.e MUx = Px. <br/> Where : X = the commodity <br/> MU = Marginal utility <br/> P = price of the commodity <br/> Therefore, a consumer who consume a single commodity such as apple will be at equilibrium when MUa = Pa</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2022 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the government imposes a minimum price on a commodity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market surplus occurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the market will be cleared in the short-run</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand occurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government regulation is no longer needed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum price is often called price floor and it is fixed by the government to protect the producer or seller. Minimum price is set above the equilibrium price and when this occur, there will be excess supply over demand i.e surplus. </div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2022 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A minimum price legislation is also called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price ceiling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price floor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price mechanism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum price is often called price floor and it is fixed by the government to protect the producer or seller. Minimum price is set above the equilibrium price and when this occur, there will be excess supply over demand i.e surplus. </div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2022 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors is not a cause of diminishing returns?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in variable inputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Land fragmentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Technological innovations</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lae of diminishing returns also known as known as law of variable proportion. It is applied to the short run analysis of production . However, the causes of diminishing returns are: fixed costs, limited demand, No change in technology,scarce factors etc.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2022 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In manufacturing, division of labour may be hindered by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excessive demand for the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low level of technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the export of goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factors that limit the application of division of labour are: size of market, production method/technology, nature of commodities, non-availability of capital, non -availability of required skilled labour, low level of technology etc.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2022 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The production cost that varies inversely with output is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average fixed cost (AFC) is the fixed cost of production divided by the quantity of output produced. As output increases, the AFC decreases because the same fixed cost is spread over more units of output. This is why it is said to vary inversely with output.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2022 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm that closes down will still incur</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm that shut down will earn zero revenue and its variable cost of producion is also zero, so the firm's total cost of production is equal to its fixed cost.  However, the firm will still incur fixed cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>2022 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sufficient condition for a firm to be in equilibrium is that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">firm must show that it is profitable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost must be equal to average revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal revenue curve is above the average revenue curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost curve cuts the marginal revenue curve from below</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm is said to be in equilibrium when it satifies the following conditions: <br/> - the first conditon for the equilibrium of the firm is that its profit should be maximum <br/> - Marginal cost should be equal to marginal revenue <br/> - Marginal cost must cut Marginal revenue from below</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2022 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative societies are formed mainly to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assist producers to maximize their profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage thrift and credit among members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote and maintain the welfare of members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">break the monopolies of private companies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative societies are formed with the aim of helping their members. It is often a voluntary association of individuals who come together with the intention of work together and to promote their economic interest.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2022 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A disadvantage of a joint-stock company is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unlimited liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of continuity when a shareholder dies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited control in management by shareholders</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The owners of the business ( shareholders) have little or no say in the affairs of the business, while the people at the helm of affairs who are not the owners may not put in their best.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2022 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The middlemen is responsible for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">providing research facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchasing raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">designing the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">breaking the bulk</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The middlemen plays the role of an intermediary in a distribution or transaction chain who facilitates interaction between the involved parties. The middlemen are the whoselars and retailers who specialise in performing activities relating to the purchase and sale of goods in the process of their flow from producer to the final buyers</div>", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN"}, {"id": "objective>Economics>2022 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major function of the retailer is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">grant credit to the wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">break bulk and sell products in small units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce cost of distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generate demand for products through advertisement</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of a retailer is selling the products in small units to the consumers/customers. They also perform several marketing functions such as sales promotion, advertising and point of purchase display etc.</div>", "topic": "DISTRIBUTIVE TRADE : THE RETAILER"}, {"id": "objective>Economics>2022 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A positive effect of a rapid population increase is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an excessive budget deficit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reduction in standard of living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a wider market for goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a higher dependency ratio</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The positive effect of the large population is that : <br/> - it increases the availability of cheap labour <br/> - It leads to the formation of the large market as investors would like to invest in a country with a large population <br/> - it motivates people to innovate</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2022 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors may not affect the efficiency of labour?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Education and training</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of welfare service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Race and colour of workforce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quality of other factor inputs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The factors affecting the efficiency of labour are: <br/> - Level of technology <br/> - Attractive wages <br/> - Conditions of service <br/> - Security of job <br/> - Education and training <br/> - Promotion</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2022 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of unemployment found among workers who leave their jobs in search of other jobs is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seasonal unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frictional unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclical unemployment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Frictional unemployment arises when a person is in between jobs. It is also a sort of unemployment where job seekers search for jobs while the jobs seek the employees or workers.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2022 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main objective of marketing boards is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accumulate revenue for government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educate farmers on pricing of cash crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilize the incomes of cash crop farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide warehousing facilities</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prime motive in the establishment of most marketing boards is to stabilize producer prices, particulary in the case of products designed primarily for those export markets in which price fluctuations are most violent.</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>2022 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The point x inside the ppc indicate? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">resources are fully utilized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the country is poor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">some resources are idle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resources are not available</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Point x inside the PPC indicates that resources are underemployed or idle. It also indicate that resources are not fully employed.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2022 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following industries will add more value to primary products?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Service industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Construction industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Processing industry</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The processing industry adds more value to primary products than the other industries listed. This is because the processing industry involves transforming raw materials into finished goods, which typically have a higher market value. For example, a coffee processing company might buy raw coffee beans, roast them, grind them, and package them for sale. Each of these steps adds value to the product, allowing the company to sell it for a higher price than the cost of the raw beans. This is known as value addition.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2022 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gross National Product (GNP) less the provision  for the wear and tear of assets is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">net present value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net national product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net factor income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net indirect taxes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net National Product is the gross national product minus depreciation i.e NNP = GNP - Depreciation or Capital consumption allowance.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2022 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of transfer payments in national income accounting is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money transferred to another country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unemployment allowance paid to the citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the amount paid to a worker on transfer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer of funds from one bank to another</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transfer payment are payment of receipts not resulting from contribution to productive activities in the economy. They are mere transfers from one person to another, for example: pension, bursary, award, gift,  unemployment benefit etc. When estimating or calculating national income, transfer payment are excluded.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2022 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Increasing national income without effective control of population size in a country can lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">higher per capita income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in poverty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased outflow of aid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">underutilization of resources</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increasing national income without effective control of population size in a country can lead to an increase in poverty. This is because if the population size is growing faster than the rate of economic growth, the per capita income (income per person) may decrease. This can lead to an increase in poverty as more people will have less income.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2022 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of  commodity money is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">currency note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobile money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Commodity money are money who has value has money and commodity e.g. gold, silver coin, diamond, cattle, bead etc.</div>", "topic": "MONEY : TYPES OF MONEY"}, {"id": "objective>Economics>2022 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If inflation is anticipated, people may</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">save more money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spend more money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">give out more loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spend less money</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anticipated inflation occurs when people know inflation is going to occur and prepare for it. For example, increased interest rates.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2022 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the Central Bank increases its bank rate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">many banks will shut down their operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customers will borrow more from banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the supply of money may be reduced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest charges by banks will fall</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A rise in the bank rate means that the interest charge from commercial banks will increase their interest which reduce the borrowing by general public and interest rate is high, so the money supply would decrease.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2022 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial banks are different from development banks in that the latter</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lend on short-term basis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pay interest on current accounts only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are mostly joint-stock companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">do not deal in foreign currencies</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial bank is the bank organized to perform public utility banking services such as accepting deposits, lending of money etc. On the other hand, development bank refers to a multi-purpose financial undertaking set up to provide financial aid to the industrial and agricultural sector, to encourage development.  <br/>  <br/> The difference is that raise funds from accepting deposit from the public while development banks borrow, grants and sells securities.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2022 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of the bank rate, cash ratio and open market operations constitute</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fiscal policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monetary policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">import policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">export policy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monetary policy refers to the policy taken by the Central Bank to control and regulate the supply of money with the public (economy). Examples are Open market operation, Bank rate, Cash reserve ratio etc.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2022 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy measures imply a change in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">only taxation to control aggregate demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank rate to influence lending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only government expenditure to regulate an economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government revenue and expenditure to regulate an economy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy is the use of government income and expenditure instrument to regulate or control the economy.  It is used to control inflation, deflation, balance of payments deficits, economic recession, unemployment, price level, GNP etc. The two most important fiscal policy tools of government are: Government expenditure and Taxation  <br/> </div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}];
